      final String fileName = '${DateTime.now().millisecondsSinceEpoch}_${_pickedFile!.name}';
      final String contentType = _pickedFile!.mimeType ?? 'application/octet-stream';

      await s3Client.putObject(
        BucketName: _awsBucketName,
        Key: fileName,
