              analysisOutput.writeln('  - Sorrow likelihood: ${face['sorrowLikelihood']}');
              analysisOutput.writeln('  - Anger likelihood: ${face['angerLikelihood']}');
              analysisOutput.writeln('  - Surprise likelihood: ${face['surpriseLikelihood']}');
            }
