          if (visionResponse['safeSearchAnnotation'] != null) {
            analysisOutput.writeln('\nSafe Search:');
            analysisOutput.writeln('  - Adult: ${visionResponse['safeSearchAnnotation']['adult']}');
            analysisOutput.writeln('  - Spoof: ${visionResponse['safeSearchAnnotation']['spoof']}');
            analysisOutput.writeln('  - Medical: ${visionResponse['safeSearchAnnotation']['medical']}');
            analysisOutput.writeln('  - Violence: ${visionResponse['safeSearchAnnotation']['violence']}');
            analysisOutput.writeln('  - Racy: ${visionResponse['safeSearchAnnotation']['racy']}');
          }

          if (analysisOutput.isEmpty) {
            analysisOutput.writeln('No specific annotations found.');
          }
        } else {
          analysisOutput.writeln('No responses from Vision API.');
        }

        setState(() {
          _visionAnalysisResult = analysisOutput.toString();
